##############################################################################
# Adaptive Rejection Sampling (ARS)
# Reference: Gilks, W. R., & Wild, P. (1992). Adaptive rejection sampling
#            for Gibbs sampling. JRSS Series C, 41(2), 337-348.
#
# Modular implementation with input validation and log-concavity checks.
##############################################################################

# --------------------------------------------------------------------------
# Module 1: Input Validation
# --------------------------------------------------------------------------

#' Validate inputs to the ars() function.
#' Checks types, ranges, and domain consistency.
validate_inputs <- function(n, f, lb, ub, x_init) {
  # n must be a positive integer
  if (!is.numeric(n) || length(n) != 1 || is.na(n)) {
    stop("'n' must be a single numeric value.")
  }
  if (n < 1 || n != floor(n)) {
    stop("'n' must be a positive integer.")
  }

  # f must be a function
  if (!is.function(f)) {
    stop("'f' must be a function (density function).")
  }

  # lb and ub must be numeric scalars (may be -Inf / Inf)
  if (!is.numeric(lb) || length(lb) != 1 || is.na(lb)) {
    stop("'lb' must be a single numeric value (may be -Inf).")
  }
  if (!is.numeric(ub) || length(ub) != 1 || is.na(ub)) {
    stop("'ub' must be a single numeric value (may be Inf).")
  }
  if (lb >= ub) {
    stop("'lb' must be strictly less than 'ub'.")
  }

  # x_init validation (if provided)
  if (!is.null(x_init)) {
    if (!is.numeric(x_init) || length(x_init) < 2) {
      stop("'x_init' must be a numeric vector with at least 2 elements.")
    }
    if (any(x_init <= lb) || any(x_init >= ub)) {
      stop("All 'x_init' values must be strictly inside (lb, ub).")
    }
  }

  invisible(TRUE)
}


# --------------------------------------------------------------------------
# Module 2: Log-density Evaluation
# --------------------------------------------------------------------------

#' Evaluate the log of the density function safely.
#' Returns -Inf for zero or negative density values.
eval_log_density <- function(f, x) {
  vals <- suppressWarnings(f(x))
  if (any(is.na(vals) | is.nan(vals))) {
    stop("Density function returned NA/NaN.")
  }
  ifelse(vals > 0, log(vals), -Inf)
}


# --------------------------------------------------------------------------
# Module 3: Log-Concavity Check
# --------------------------------------------------------------------------

#' Check log-concavity: for sorted abscissae x with log-density h,
#' the slopes of the secant lines must be non-increasing.
check_log_concavity <- function(x, h) {
  if (length(x) < 3) return(invisible(TRUE))
  slopes <- diff(h) / diff(x)
  # Allow small numerical tolerance
  if (any(diff(slopes) > 1e-6)) {
    stop("Log-concavity violated: the supplied density does not appear to be log-concave.")
  }
  invisible(TRUE)
}


# --------------------------------------------------------------------------
# Module 4: Initialize Abscissae
# --------------------------------------------------------------------------

#' Choose starting abscissae if not supplied by user.
#' We need at least two points in the interior of (lb, ub).
initialize_abscissae <- function(f, lb, ub, x_init) {
  if (!is.null(x_init)) {
    x_init <- sort(x_init)
    h <- eval_log_density(f, x_init)
    if (any(h == -Inf)) {
      stop("Density is zero at one or more initial abscissae. Choose different starting points.")
    }
    return(list(x = x_init, h = h))
  }

  # Automatic initialization: try to find points with positive density
  # Strategy: try the mode region first via a grid search
  if (is.finite(lb) && is.finite(ub)) {
    candidates <- seq(lb + (ub - lb) * 0.1, ub - (ub - lb) * 0.1, length.out = 20)
  } else if (is.finite(lb)) {
    candidates <- lb + c(0.5, 1, 2, 5, 10)
  } else if (is.finite(ub)) {
    candidates <- ub - c(0.5, 1, 2, 5, 10)
  } else {
    candidates <- c(-4, -2, -1, -0.5, 0, 0.5, 1, 2, 4)
  }

  h_cand <- eval_log_density(f, candidates)
  good <- which(h_cand > -Inf)
  if (length(good) < 2) {
    stop("Could not find at least 2 initial points with positive density. Supply 'x_init'.")
  }

  # Pick 2-5 well-spread points with positive density
  sel <- good
  if (length(sel) > 5) {
    sel <- sel[round(seq(1, length(sel), length.out = 5))]
  }

  x_sel <- candidates[sel]
  h_sel <- h_cand[sel]

  # Ensure that for unbounded domains, the boundary slopes have correct sign
  # If lb == -Inf, we need h'(x[1]) > 0 (increasing on the left)
  # If ub == Inf,  we need h'(x[k]) < 0 (decreasing on the right)
  if (!is.finite(lb) && length(x_sel) >= 2) {
    slope_left <- (h_sel[2] - h_sel[1]) / (x_sel[2] - x_sel[1])
    if (slope_left <= 0) {
      # Try shifting left point further left
      trial <- x_sel[1] - abs(x_sel[2] - x_sel[1])
      h_trial <- eval_log_density(f, trial)
      if (h_trial > -Inf && h_trial < h_sel[1]) {
        x_sel <- c(trial, x_sel)
        h_sel <- c(h_trial, h_sel)
      }
    }
  }

  if (!is.finite(ub) && length(x_sel) >= 2) {
    k <- length(x_sel)
    slope_right <- (h_sel[k] - h_sel[k - 1]) / (x_sel[k] - x_sel[k - 1])
    if (slope_right >= 0) {
      trial <- x_sel[k] + abs(x_sel[k] - x_sel[k - 1])
      h_trial <- eval_log_density(f, trial)
      if (h_trial > -Inf && h_trial < h_sel[k]) {
        x_sel <- c(x_sel, trial)
        h_sel <- c(h_sel, h_trial)
      }
    }
  }

  list(x = x_sel, h = h_sel)
}


# --------------------------------------------------------------------------
# Module 5: Upper Hull (Piecewise-Linear Envelope)
# --------------------------------------------------------------------------

#' Compute the upper hull from sorted abscissae x and log-density h.
#' Returns a list with slopes, intercepts, and intersection points z.
compute_upper_hull <- function(x, h, lb, ub) {
  k <- length(x)
  # Slopes and intercepts of tangent lines through consecutive pairs
  slopes <- diff(h) / diff(x)
  # Each piece j has equation: u_j(t) = h[j] + slopes[j] * (t - x[j])
  # Or equivalently: u_j(t) = slopes[j] * t + (h[j] - slopes[j] * x[j])
  intercepts <- h[1:(k - 1)] - slopes * x[1:(k - 1)]

  # Intersection points z between consecutive pieces
  # u_j(z) = u_{j+1}(z)
  if (k > 2) {
    z <- numeric(k - 2)
    for (j in 1:(k - 2)) {
      if (abs(slopes[j] - slopes[j + 1]) < 1e-15) {
        z[j] <- (x[j + 1] + x[j]) / 2
      } else {
        z[j] <- (intercepts[j + 1] - intercepts[j]) / (slopes[j] - slopes[j + 1])
      }
    }
  } else {
    z <- numeric(0)
  }

  # The full set of breakpoints for the piecewise envelope
  breaks <- c(lb, z, ub)

  list(slopes = slopes, intercepts = intercepts, z = z, breaks = breaks)
}


# --------------------------------------------------------------------------
# Module 6: Lower Hull (Piecewise-Linear Squeezing Function)
# --------------------------------------------------------------------------

#' Evaluate the lower hull (squeezing function) at point t.
#' Returns -Inf outside [x[1], x[k]].
eval_lower_hull <- function(t, x, h) {
  k <- length(x)
  if (t < x[1] || t > x[k]) return(-Inf)

  # Find which segment t falls in
  j <- findInterval(t, x, rightmost.closed = TRUE)
  j <- min(j, k - 1)
  j <- max(j, 1)

  # Linear interpolation
  h[j] + (h[j + 1] - h[j]) / (x[j + 1] - x[j]) * (t - x[j])
}


# --------------------------------------------------------------------------
# Module 7: Evaluate Upper Hull at a Point
# --------------------------------------------------------------------------

#' Evaluate the upper hull at point t.
eval_upper_hull <- function(t, hull, x, h) {
  # Find which piece t belongs to
  j <- findInterval(t, hull$breaks, rightmost.closed = TRUE)
  j <- max(1, min(j, length(hull$slopes)))
  hull$slopes[j] * t + hull$intercepts[j]
}


# --------------------------------------------------------------------------
# Module 8: Sample from the Upper Hull (Piecewise-Exponential)
# --------------------------------------------------------------------------

#' Sample one point from the piecewise-exponential distribution defined
#' by the upper hull. Also returns the log of the proposal density
#' (unnormalized) for the acceptance test.
sample_upper_hull <- function(hull, x, h, lb, ub) {
  k <- length(hull$slopes)
  breaks <- hull$breaks

  # Compute (unnormalized) integral of exp(u(t)) on each piece
  log_integrals <- numeric(k)
  for (j in 1:k) {
    a <- breaks[j]
    b <- breaks[j + 1]
    sj <- hull$slopes[j]
    cj <- hull$intercepts[j]

    if (abs(sj) < 1e-12) {
      # Nearly flat: integral = exp(cj) * (b - a)
      if (is.finite(a) && is.finite(b)) {
        log_integrals[j] <- cj + log(b - a)
      } else {
        log_integrals[j] <- -Inf  # Improper with zero slope — shouldn't happen if log-concave
      }
    } else {
      # Integral of exp(sj * t + cj) from a to b = exp(cj)/sj * [exp(sj*b) - exp(sj*a)]
      if (!is.finite(a)) {
        # a = -Inf: need sj > 0 for convergence
        if (sj > 0) {
          log_integrals[j] <- cj + sj * b - log(sj)
        } else {
          log_integrals[j] <- -Inf
        }
      } else if (!is.finite(b)) {
        # b = Inf: need sj < 0 for convergence
        if (sj < 0) {
          log_integrals[j] <- cj + sj * a - log(-sj)
        } else {
          log_integrals[j] <- -Inf
        }
      } else {
        # Both finite
        log_val_b <- sj * b
        log_val_a <- sj * a
        log_diff <- log_val_b + log(1 - exp(log_val_a - log_val_b))
        if (sj > 0) {
          log_integrals[j] <- cj + log_diff - log(sj)
        } else {
          log_integrals[j] <- cj + log_val_a + log(1 - exp(log_val_b - log_val_a)) - log(-sj)
        }
      }
    }
  }

  # Normalize to get piece probabilities
  max_li <- max(log_integrals[is.finite(log_integrals)])
  weights <- exp(log_integrals - max_li)
  weights[!is.finite(weights)] <- 0
  probs <- weights / sum(weights)

  # Select a piece
  j <- sample.int(k, size = 1, prob = probs)

  a <- breaks[j]
  b <- breaks[j + 1]
  sj <- hull$slopes[j]
  cj <- hull$intercepts[j]

  # Sample from truncated exponential on [a, b] with rate sj
  u <- runif(1)
  if (abs(sj) < 1e-12) {
    # Uniform on [a, b]
    t_star <- a + u * (b - a)
  } else {
    if (!is.finite(a)) {
      # a = -Inf, sj > 0: CDF = exp(sj*(t - b)), sample: t = b + log(u)/sj
      t_star <- b + log(u) / sj
    } else if (!is.finite(b)) {
      # b = Inf, sj < 0: CDF = 1 - exp(sj*(t - a)), sample: t = a + log(1-u)/sj ...
      # Actually: t = a - log(1 - u) / (-sj) = a + log(1-u)/sj
      t_star <- a + log(1 - u) / sj
    } else {
      # Inverse CDF for truncated exponential
      exp_a <- exp(sj * a)
      exp_b <- exp(sj * b)
      t_star <- log(exp_a + u * (exp_b - exp_a)) / sj
    }
  }

  # Log-density of the upper hull at t_star
  log_u_star <- sj * t_star + cj

  list(x_star = t_star, log_u = log_u_star)
}


# --------------------------------------------------------------------------
# Module 9: Update Step (Add New Abscissa)
# --------------------------------------------------------------------------

#' Insert a new abscissa into the sorted set and recompute hulls.
update_abscissae <- function(x_star, h_star, x, h) {
  pos <- findInterval(x_star, x) + 1
  x_new <- append(x, x_star, after = pos - 1)
  h_new <- append(h, h_star, after = pos - 1)
  list(x = x_new, h = h_new)
}


# --------------------------------------------------------------------------
# Module 10: Main ARS Function
# --------------------------------------------------------------------------

#' Adaptive Rejection Sampling
#'
#' @param n       Number of samples to draw (positive integer).
#' @param f       Density function (possibly unnormalized). Must be vectorized.
#' @param lb      Lower bound of the support (may be -Inf).
#' @param ub      Upper bound of the support (may be Inf).
#' @param x_init  Optional numeric vector of initial abscissae (at least 2).
#'                Must lie strictly inside (lb, ub).
#' @return Numeric vector of n samples from f.
ars <- function(n, f, lb = -Inf, ub = Inf, x_init = NULL) {

  # --- Step 1: Validate inputs ---
  validate_inputs(n, f, lb, ub, x_init)

  # --- Step 2: Initialize abscissae ---
  init <- initialize_abscissae(f, lb, ub, x_init)
  x_abs <- init$x
  h_abs <- init$h

  # --- Step 3: Check initial log-concavity ---
  check_log_concavity(x_abs, h_abs)

  # --- Step 4: Sampling loop ---
  samples <- numeric(n)
  i <- 1

  while (i <= n) {
    # Compute upper hull
    hull <- compute_upper_hull(x_abs, h_abs, lb, ub)

    # Sample from upper hull
    proposal <- sample_upper_hull(hull, x_abs, h_abs, lb, ub)
    x_star <- proposal$x_star
    log_u_star <- proposal$log_u

    # Evaluate lower hull (squeezing test)
    l_star <- eval_lower_hull(x_star, x_abs, h_abs)

    w <- runif(1)

    if (log(w) <= l_star - log_u_star) {
      # Accepted by squeezing test — no density evaluation needed
      samples[i] <- x_star
      i <- i + 1
    } else {
      # Need to evaluate the true log-density
      h_star <- eval_log_density(f, x_star)

      if (log(w) <= h_star - log_u_star) {
        # Accepted by rejection test
        samples[i] <- x_star
        i <- i + 1
      }

      # Update abscissae with the new point
      updated <- update_abscissae(x_star, h_star, x_abs, h_abs)
      x_abs <- updated$x
      h_abs <- updated$h

      # Check log-concavity with new point
      check_log_concavity(x_abs, h_abs)
    }
  }

  samples
}


# --------------------------------------------------------------------------
# Module 11: Test Function
# --------------------------------------------------------------------------

#' Run formal tests comparing ARS output against known distributions.
#' Uses Kolmogorov-Smirnov tests and moment checks.
test <- function() {
  cat("============================================================\n")
  cat("  Adaptive Rejection Sampler (ARS) — Test Suite\n")
  cat("============================================================\n\n")

  n_samples <- 5000
  ks_alpha <- 0.001  # Very conservative to avoid false failures

  # ------------------------------------------------------------------
  # Helper: run a single distribution test
  # ------------------------------------------------------------------
  run_distribution_test <- function(test_name, f, lb, ub, ref_cdf,
                                     true_mean, true_sd, x_init = NULL) {
    cat(sprintf("Testing: %s\n", test_name))

    result <- tryCatch({
      samples <- ars(n = n_samples, f = f, lb = lb, ub = ub, x_init = x_init)

      # KS test against reference CDF
      ks <- ks.test(samples, ref_cdf)

      # Moment checks
      samp_mean <- mean(samples)
      samp_sd <- sd(samples)

      cat(sprintf("  Sample mean = %.4f (true = %.4f)\n", samp_mean, true_mean))
      cat(sprintf("  Sample SD   = %.4f (true = %.4f)\n", samp_sd, true_sd))
      cat(sprintf("  KS p-value  = %.4f\n", ks$p.value))

      # Pass conditions: KS test not rejected AND moments are reasonable
      mean_ok <- abs(samp_mean - true_mean) < 3 * true_sd / sqrt(n_samples) + 0.1
      sd_ok <- abs(samp_sd - true_sd) / true_sd < 0.2
      ks_ok <- ks$p.value > ks_alpha

      if (ks_ok && mean_ok && sd_ok) {
        cat(sprintf("%s: PASS\n\n", test_name))
        return(list(passed = TRUE, samples = samples))
      } else {
        reasons <- c()
        if (!ks_ok) reasons <- c(reasons, "KS test rejected")
        if (!mean_ok) reasons <- c(reasons, "mean off")
        if (!sd_ok) reasons <- c(reasons, "SD off")
        cat(sprintf("%s: FAIL (%s)\n\n", test_name, paste(reasons, collapse = ", ")))
        return(list(passed = FALSE, samples = samples))
      }
    }, error = function(e) {
      cat(sprintf("  Error: %s\n", e$message))
      cat(sprintf("%s: FAIL (error)\n\n", test_name))
      return(list(passed = FALSE, samples = NULL))
    })

    result
  }

  passed <- 0
  total <- 0

  # ------------------------------------------------------------------
  # Test 1: Standard Normal N(0,1)
  # ------------------------------------------------------------------
  total <- total + 1
  res <- run_distribution_test(
    test_name = "Standard_Normal",
    f = dnorm,
    lb = -Inf, ub = Inf,
    ref_cdf = pnorm,
    true_mean = 0, true_sd = 1
  )
  if (res$passed) passed <- passed + 1
  # Save samples
  if (!is.null(res$samples)) {
    writeLines(as.character(res$samples), "/app/normal_samples.txt")
  }

  # ------------------------------------------------------------------
  # Test 2: Normal(3, 2) — shifted/scaled
  # ------------------------------------------------------------------
  total <- total + 1
  res <- run_distribution_test(
    test_name = "Normal_mu3_sd2",
    f = function(x) dnorm(x, mean = 3, sd = 2),
    lb = -Inf, ub = Inf,
    ref_cdf = function(x) pnorm(x, mean = 3, sd = 2),
    true_mean = 3, true_sd = 2
  )
  if (res$passed) passed <- passed + 1

  # ------------------------------------------------------------------
  # Test 3: Exponential(1) on (0, Inf)
  # ------------------------------------------------------------------
  total <- total + 1
  res <- run_distribution_test(
    test_name = "Exponential_rate1",
    f = dexp,
    lb = 0, ub = Inf,
    ref_cdf = pexp,
    true_mean = 1, true_sd = 1,
    x_init = c(0.5, 1, 3)
  )
  if (res$passed) passed <- passed + 1
  # Save exponential samples
  if (!is.null(res$samples)) {
    writeLines(as.character(res$samples), "/app/exponential_samples.txt")
  }

  # ------------------------------------------------------------------
  # Test 4: Gamma(5, 1) — shape > 1, log-concave
  # ------------------------------------------------------------------
  total <- total + 1
  res <- run_distribution_test(
    test_name = "Gamma_shape5_rate1",
    f = function(x) dgamma(x, shape = 5, rate = 1),
    lb = 0, ub = Inf,
    ref_cdf = function(x) pgamma(x, shape = 5, rate = 1),
    true_mean = 5, true_sd = sqrt(5),
    x_init = c(1, 3, 5, 8)
  )
  if (res$passed) passed <- passed + 1

  # ------------------------------------------------------------------
  # Test 5: Beta(2, 5) on (0, 1)
  # ------------------------------------------------------------------
  total <- total + 1
  res <- run_distribution_test(
    test_name = "Beta_2_5",
    f = function(x) dbeta(x, 2, 5),
    lb = 0, ub = 1,
    ref_cdf = function(x) pbeta(x, 2, 5),
    true_mean = 2 / 7, true_sd = sqrt(10 / (49 * 8)),
    x_init = c(0.1, 0.3, 0.6)
  )
  if (res$passed) passed <- passed + 1

  # ------------------------------------------------------------------
  # Test 6: Truncated Normal on (-2, 2)
  # ------------------------------------------------------------------
  total <- total + 1
  # Truncated N(0,1) on (-2,2): mean=0, sd ~ 0.72
  Z <- pnorm(2) - pnorm(-2)
  trunc_sd <- sqrt(1 - 2 * 2 * dnorm(2) / Z)
  res <- run_distribution_test(
    test_name = "Truncated_Normal_-2_2",
    f = dnorm,
    lb = -2, ub = 2,
    ref_cdf = function(x) {
      (pnorm(pmin(pmax(x, -2), 2)) - pnorm(-2)) / Z
    },
    true_mean = 0, true_sd = trunc_sd,
    x_init = c(-1, 0, 1)
  )
  if (res$passed) passed <- passed + 1

  # ------------------------------------------------------------------
  # Test 7: Logistic distribution
  # ------------------------------------------------------------------
  total <- total + 1
  res <- run_distribution_test(
    test_name = "Logistic_0_1",
    f = dlogis,
    lb = -Inf, ub = Inf,
    ref_cdf = plogis,
    true_mean = 0, true_sd = pi / sqrt(3)
  )
  if (res$passed) passed <- passed + 1

  # ==================================================================
  # Input Validation Tests
  # ==================================================================
  cat("--- Input Validation Tests ---\n\n")

  # Test: negative n
  total <- total + 1
  cat("Testing: Negative_n_rejected\n")
  tryCatch({
    ars(n = -5, f = dnorm)
    cat("Negative_n_rejected: FAIL (no error raised)\n\n")
  }, error = function(e) {
    cat(sprintf("  Caught: %s\n", e$message))
    cat("Negative_n_rejected: PASS\n\n")
    passed <<- passed + 1
  })

  # Test: non-function f
  total <- total + 1
  cat("Testing: Non_function_f_rejected\n")
  tryCatch({
    ars(n = 100, f = "not_a_function")
    cat("Non_function_f_rejected: FAIL (no error raised)\n\n")
  }, error = function(e) {
    cat(sprintf("  Caught: %s\n", e$message))
    cat("Non_function_f_rejected: PASS\n\n")
    passed <<- passed + 1
  })

  # Test: lb >= ub
  total <- total + 1
  cat("Testing: Invalid_domain_rejected\n")
  tryCatch({
    ars(n = 100, f = dnorm, lb = 5, ub = 2)
    cat("Invalid_domain_rejected: FAIL (no error raised)\n\n")
  }, error = function(e) {
    cat(sprintf("  Caught: %s\n", e$message))
    cat("Invalid_domain_rejected: PASS\n\n")
    passed <<- passed + 1
  })

  # Test: non-log-concave density (Cauchy)
  total <- total + 1
  cat("Testing: Non_log_concave_rejected\n")
  tryCatch({
    ars(n = 100, f = dcauchy, lb = -Inf, ub = Inf, x_init = c(-5, -1, 0, 1, 5))
    cat("Non_log_concave_rejected: FAIL (no error raised)\n\n")
  }, error = function(e) {
    cat(sprintf("  Caught: %s\n", e$message))
    cat("Non_log_concave_rejected: PASS\n\n")
    passed <<- passed + 1
  })

  # Test: n = 0
  total <- total + 1
  cat("Testing: Zero_n_rejected\n")
  tryCatch({
    ars(n = 0, f = dnorm)
    cat("Zero_n_rejected: FAIL (no error raised)\n\n")
  }, error = function(e) {
    cat(sprintf("  Caught: %s\n", e$message))
    cat("Zero_n_rejected: PASS\n\n")
    passed <<- passed + 1
  })

  # Test: x_init outside domain
  total <- total + 1
  cat("Testing: Init_outside_domain_rejected\n")
  tryCatch({
    ars(n = 100, f = dnorm, lb = 0, ub = 10, x_init = c(-1, 5))
    cat("Init_outside_domain_rejected: FAIL (no error raised)\n\n")
  }, error = function(e) {
    cat(sprintf("  Caught: %s\n", e$message))
    cat("Init_outside_domain_rejected: PASS\n\n")
    passed <<- passed + 1
  })

  # ==================================================================
  # Module Tests
  # ==================================================================
  cat("--- Module Tests ---\n\n")

  # Test: upper/lower hull evaluation
  total <- total + 1
  cat("Testing: Hull_evaluation\n")
  tryCatch({
    x_test <- c(-2, -1, 0, 1, 2)
    h_test <- eval_log_density(dnorm, x_test)
    hull <- compute_upper_hull(x_test, h_test, -Inf, Inf)

    # Upper hull must be >= log-density at all abscissae
    for (xi in seq(-3, 3, by = 0.5)) {
      u_val <- eval_upper_hull(xi, hull, x_test, h_test)
      h_val <- eval_log_density(dnorm, xi)
      if (u_val < h_val - 1e-6) {
        stop(sprintf("Upper hull below log-density at x=%.2f: u=%.4f < h=%.4f", xi, u_val, h_val))
      }
    }

    # Lower hull must be <= log-density at interior points
    for (xi in seq(-1.5, 1.5, by = 0.5)) {
      l_val <- eval_lower_hull(xi, x_test, h_test)
      h_val <- eval_log_density(dnorm, xi)
      if (l_val > h_val + 1e-6) {
        stop(sprintf("Lower hull above log-density at x=%.2f: l=%.4f > h=%.4f", xi, l_val, h_val))
      }
    }

    cat("  Upper hull >= log-density: OK\n")
    cat("  Lower hull <= log-density: OK\n")
    cat("Hull_evaluation: PASS\n\n")
    passed <<- passed + 1
  }, error = function(e) {
    cat(sprintf("  Error: %s\n", e$message))
    cat("Hull_evaluation: FAIL\n\n")
  })

  # Test: log-concavity detection
  total <- total + 1
  cat("Testing: Log_concavity_detection\n")
  tryCatch({
    # Non-log-concave: bimodal mixture
    x_bimodal <- c(-3, -1, 0, 1, 3)
    h_bimodal <- log(0.5 * dnorm(x_bimodal, -2) + 0.5 * dnorm(x_bimodal, 2))

    err_caught <- FALSE
    tryCatch({
      check_log_concavity(x_bimodal, h_bimodal)
    }, error = function(e) {
      err_caught <<- TRUE
    })

    if (err_caught) {
      cat("  Bimodal density correctly rejected\n")
      cat("Log_concavity_detection: PASS\n\n")
      passed <<- passed + 1
    } else {
      cat("  Bimodal density was NOT rejected\n")
      cat("Log_concavity_detection: FAIL\n\n")
    }
  }, error = function(e) {
    cat(sprintf("  Error: %s\n", e$message))
    cat("Log_concavity_detection: FAIL\n\n")
  })

  # Test: update_abscissae maintains sorted order
  total <- total + 1
  cat("Testing: Update_abscissae_sorted\n")
  tryCatch({
    x0 <- c(1, 3, 5, 7)
    h0 <- c(-1, -0.5, -0.5, -1)
    upd <- update_abscissae(4, -0.6, x0, h0)
    if (all(diff(upd$x) > 0) && length(upd$x) == 5 && upd$x[3] == 4) {
      cat("  Sorted order maintained after insertion\n")
      cat("Update_abscissae_sorted: PASS\n\n")
      passed <<- passed + 1
    } else {
      cat("Update_abscissae_sorted: FAIL\n\n")
    }
  }, error = function(e) {
    cat(sprintf("  Error: %s\n", e$message))
    cat("Update_abscissae_sorted: FAIL\n\n")
  })

  # ==================================================================
  # Summary
  # ==================================================================
  cat("============================================================\n")
  cat(sprintf("  Results: %d / %d tests passed\n", passed, total))
  cat("============================================================\n")

  invisible(passed == total)
}


