ecewise-Linear Envelope)", " # --------------------------------------------------------------------------", "+#", "+# For a log-concave function h with abscissae x_1 < ... < x_k:", "+# Chord L_j connects (x_j, h_j) and (x_{j+1}, h_{j+1}), slope s_j.", "+# By concavity, L_j lies ABOVE h outside [x_j, x_{j+1}] and BELOW inside.", "+#", "+# Upper hull construction:", "+# - Left tail [lb, x_1]:        L_1 (extended left)", "+# - [x_1, x_2]:                 L_2 (extended left of x_2)  [k >= 3]", "+# - [x_j, x_{j+1}] (interior): min(L_{j-1}, L_{j+1}) split at z_j", "+# - [x_{k-1}, x_k]:            L_{k-2} (extended right of x_{k-1})", "+# - Right tail [x_k, ub]:       L_{k-1} (extended right)", " ", "-#' Compute the upper hull from sorted abscissae x and log-density h.", "-#' Returns a list with slopes, intercepts, and intersection points z.", " compute_upper_hull <- function(x, h, lb, ub) {", "   k <- length(x)", "-  # Slopes and intercepts of tangent lines through consecutive pairs", "-  slopes <- diff(h) / diff(x)", "-  # Each piece j has equation: u_j(t) = h[j] + slopes[j] * (t - x[j])", "-  # Or equivalently: u_j(t) = slopes[j] * t + (h[j] - slopes[j] * x[j])", "-  intercepts <- h[1:(k - 1)] - slopes * x[1:(k - 1)]", "+  s <- diff(h) / diff(x)", "+  cc <- h[1:(k - 1)] - s * x[1:(k - 1)]", " ", "-  # Intersection points z between consecutive pieces", "-  # u_j(z) = u_{j+1}(z)", "-  if (k > 2) {", "-    z <- numeric(k - 2)", "-    for (j in 1:(k - 2)) {", "-      if (abs(slopes[j] - slopes[j + 1]) < 1e-15) {", "-        z[j] <- (x[j + 1] + x[j]) / 2", "-      } else {", "-        z[j] <- (intercepts[j + 1] - intercepts[j]) / (slopes[j] - slopes[j + 1])", "+  p_slopes <- numeric(0)", "+  p_intercepts <- numeric(0)", "+  p_left <- numeric(0)", "+  p_right <- numeric(0)", "+", "+  add_piece <- function(sl, ic, l, r) {", "+    p_slopes <<- c(p_slopes, sl)", "+    p_intercepts <<- c(p_intercepts, ic)", "+    p_left <<- c(p_left, l)", "+    p_right <<- c(p_right, r)", "+  }", "+", "+  # Left tail", "+  add_piece(s[1], cc[1], lb, x[1])", "+", "+  if (k >= 3) {", "+    # First boundary interval [x_1, x_2]: use chord L_2", "+    add_piece(s[2], cc[2], x[1], x[2])", "+", "+    # Interior intervals", "+    if (k >= 4) {", "+      for (j in 2:(k - 2)) {", "+        z <- (cc[j + 1] - cc[j - 1]) / (s[j - 1] - s[j + 1])", "+        z <- max(z, x[j])", "+        z <- min(z, x[j + 1])", "+        add_piece(s[j - 1], cc[j - 1], x[j], z)", "+        add_piece(s[j + 1], cc[j + 1], z, x[j + 1])", "       }", "     }", "+", "+    # Last boundary interval [x_{k-1}, x_k]: use chord L_{k-2}", "+    add_piece(s[k - 2], cc[k - 2], x[k - 1], x[k])", "   } else {", "-    z <- numeric(0)", "+    # k == 2: use the single chord for the interior (crude)", "+    add_piece(s[1], cc[1], x[1], x[2])", "   }", " ", "-  # The full set of breakpoints for the piecewise envelope", "-  breaks <- c(lb, z, ub)", "+  # Right tail", "+  add_piece(s[k - 1], cc[k - 1], x[k], ub)", " ", "-  list(slopes = slopes, intercepts = intercepts, z = z, breaks = breaks)", "+  list(", "+    slopes = p_slopes, intercepts = p_intercepts,", "+    left = p_left, right = p_right,", "+    n_pieces = length(p_slopes)", "+  )", " }", " ", "+# --------------------------------------------------------------------------", "+# Module 6: Evaluate Upper Hull at a Point", "+# --------------------------------------------------------------------------", " ", "+eval_upper_hull <- function(t, hull) {", "+  for (i in seq_len(hull$n_pieces)) {", "+    if (t >= hull$left[i] && t <= hull$right[i]) {", "+      return(hull$slopes[i] * t + hull$intercepts[i])", "+    }", "+  }", "+  # Fallback: find closest piece", "+  for (i in seq_len(hull$n_pieces)) {", "+    if ((i == 1 && t <= hull$right[i]) ||", "+        (i == hull$n_pieces && t >= hull$left[i])) {", "+      return(hull$slopes[i] * t + hull$intercepts[i])", "+    }", "+  }", "+  return(Inf)", "+}", "+", " # --------------------------------------------------------------------------", "-# Module 6: Lower Hull (Piecewise-Linear Squeezing Function)", "+# Module 7: Lower Hull (Squeezing Function)", " # --------------------------------------------------------------------------", " ", "-#' Evaluate the lower hull (squeezing function) at point t.", "-#' Returns -Inf outside [x[1], x[k]].", " eval_lower_hull <- function(t, x, h) {", "   k <- length(x)", "   if (t < x[1] || t > x[k]) return(-Inf)", "-", "-  # Find which segment t falls in", "   j <- findInterval(t, x, rightmost.closed = TRUE)", "   j <- min(j, k - 1)", "   j <- max(j, 1)", "-", "-  # Linear interpolation", "   h[j] + (h[j + 1] - h[j]) / (x[j + 1] - x[j]) * (t - x[j])", " }", " ", "-", " # --------------------------------------------------------------------------", "-# Module 7: Evaluate Upper Hull at a Point", "+# Module 8: Sample from Upper Hull", " # --------------------------------------------------------------------------", " ", "-#' Evaluate the upper hull at point t.", "-eval_upper_hull <- function(t, hull, x, h) {", "-  # Find which piece t belongs to", "-  j <- findInterval(t, hull$breaks, rightmost.closed = TRUE)", "-  j <- max(1, min(j, length(hull$slopes)))", "-  hull$slopes[j] * t + hull$intercepts[j]", "-}", "+sample_upper_hull <- function(hull) {", "+  np <- hull$n_pieces", " ", "+  # Compute log-integral of exp(s*t + c) on each piece", "+  log_integrals <- numeric(np)", "+  for (i in 1:np) {", "+    a <- hull$left[i]", "+    b <- hull$right[i]", "+    si <- hull$slopes[i]", "+    ci <- hull$intercepts[i]", " ", "-# --------------------------------------------------------------------------", "-# Module 8: Sample from the Upper Hull (Piecewise-Exponential)", "-# --------------------------------------------------------------------------", "+    if (!is.finite(a) && !is.finite(b)) {", "+      log_integrals[i] <- -Inf", "+      next", "+    }", " ", "-#' Sample one point from the piecewise-exponential distribution defined", "-#' by the upper hull. Also returns the log of the proposal density", "-#' (unnormalized) for the acceptance test.", "-sample_upper_hull <- function(hull, x, h, lb, ub) {", "-  k <- length(hull$slopes)", "-  breaks <- hull$breaks", "-", "-  # Compute (unnormalized) integral of exp(u(t)) on each piece", "-  log_integrals <- numeric(k)", "-  for (j in 1:k) {", "-    a <- breaks[j]", "-    b <- breaks[j + 1]", "-    sj <- hull$slopes[j]", "-    cj <- hull$intercepts[j]", "-", "-    if (abs(sj) < 1e-12) {", "-      # Nearly flat: integral = exp(cj) * (b - a)", "+    if (abs(si) < 1e-12) {", "       if (is.finite(a) && is.finite(b)) {", "-        log_integrals[j] <- cj + log(b - a)", "+        log_integrals[i] <- ci + log(max(b - a, 1e-300))", "       } else {", "-        log_integrals[j] <- -Inf  # Improper with zero slope — shouldn't happen if log-concave", "+        log_integrals[i] <- -Inf", "       }", "     } else {", "-      # Integral of exp(sj * t + cj) from a to b = exp(cj)/sj * [exp(sj*b) - exp(sj*a)]", "       if (!is.finite(a)) {", "-        # a = -Inf: need sj > 0 for convergence", "-        if (sj > 0) {", "-          log_integrals[j] <- cj + sj * b - log(sj)", "+        if (si > 0) {", "+          log_integrals[i] <- ci + si * b - log(si)", "         } else {", "-          log_integrals[j] <- -Inf", "+          log_integrals[i] <- -Inf", "         }", "       } else if (!is.finite(b)) {", "-        # b = Inf: need sj < 0 for convergence", "-        if (sj < 0) {", "-          log_integrals[j] <- cj + sj * a - log(-sj)", "+        if (si < 0) {", "+          log_integrals[i] <- ci + si * a - log(-si)", "         } else {", "-          log_integrals[j] <- -Inf", "+          log_integrals[i] <- -Inf", "         }", "       } else {", "-        # Both finite", "-        log_val_b <- sj * b", "-        log_val_a <- sj * a", "-        log_diff <- log_val_b + log(1 - exp(log_val_a - log_val_b))", "-        if (sj > 0) {", "-          log_integrals[j] <- cj + log_diff - log(sj)", "+        # Both finite: integral = exp(ci)/si * [exp(si*b) - exp(si*a)]", "+        if (si > 0) {", "+          log_integrals[i] <- ci + si * b + log(1 - exp(si * (a - b))) - log(si)", "         } else {", "-          log_integrals[j] <- cj + log_val_a + log(1 - exp(log_val_b - log_val_a)) - log(-sj)", "+          log_integrals[i] <- ci + si * a + log(1 - exp(si * (b - a))) - log(-si)", "         }", "       }", "     }", "   }", " ", "   # Normalize to get piece probabilities", "-  max_li <- max(log_integrals[is.finite(log_integrals)])", "-  weights <- exp(log_integrals - max_li)", "-  weights[!is.finite(weights)] <- 0", "+  valid <- which(is.finite(log_integrals) & log_integrals > -Inf)", "+  if (length(valid) == 0) stop("No valid upper hull pieces for sampling.")", "+", "+  max_li <- max(log_integrals[valid])", "+  weights <- rep(0, np)", "+  weights[valid] <- exp(log_integrals[valid] - max_li)", "   probs <- weights / sum(weights)", " ", "-  # Select a piece", "-  j <- sample.int(k, size = 1, prob = probs)", "+  # Select piece", "+  idx <- sample.int(np, size = 1, prob = probs)", "+  a <- hull$left[idx]", "+  b <- hull$right[idx]", "+  si <- hull$slopes[idx]", "+  ci <- hull$intercepts[idx]", " ", "-  a <- breaks[j]", "-  b <- breaks[j + 1]", "-  sj <- hull$slopes[j]", "-  cj <- hull$intercepts[j]", "-", "-  # Sample from truncated exponential on [a, b] with rate sj", "+  # Sample from truncated exponential on [a, b]", "   u <- runif(1)", "-  if (abs(sj) < 1e-12) {", "-    # Uniform on [a, b]", "+  if (abs(si) < 1e-12) {", "     t_star <- a + u * (b - a)", "   } else {", "     if (!is.finite(a)) {", "-      # a = -Inf, sj > 0: CDF = exp(sj*(t - b)), sample: t = b + log(u)/sj", "-      t_star <- b + log(u) / sj", "+      t_star <- b + log(u) / si", "     } else if (!is.finite(b)) {", "-      # b = Inf, sj < 0: CDF = 1 - exp(sj*(t - a)), sample: t = a + log(1-u)/sj ...", "-      # Actually: t = a - log(1 - u) / (-sj) = a + log(1-u)/sj", "-      t_star <- a + log(1 - u) / s